sql:
SELECT name, experience_years 
FROM scientists 
WHERE experience_years = (SELECT MAX(experience_years) FROM scientists);

SELECT a.user_id, COUNT(a.log_id) AS total_logs, COUNT(DISTINCT a.tech_id) AS unique_technologies
FROM access_logs a
GROUP BY a.user_id;

SELECT COUNT(DISTINCT rp.scientist_id) AS num_unique_scientists
FROM research_projects rp
WHERE rp.tech_id = 0;

SELECT scientists.name, scientists.expertise, scientists.affiliation
FROM scientists
WHERE scientists.current_project_id IS NULL;

SELECT tech_id, tech_name, cost, tier, effects_unlocks, prerequisites, description, research_area, impact_on_empire, estimated_completion_date, last_updated, status
FROM technologies
WHERE cost > (SELECT AVG(cost) FROM technologies);

SELECT scientists.name, research_projects.tech_id
FROM scientists
JOIN research_projects ON scientists.scientist_id = research_projects.scientist_id;

SELECT technologies.tech_name, technologies.cost, effects.effect_description, effects.effect_magnitude
FROM technologies
INNER JOIN effects ON technologies.tech_id = effects.tech_id;

SELECT expertise, AVG(experience_years) AS avg_experience
FROM scientists
GROUP BY expertise;
